package io.airbyte.integrations.destination.customerio.io.airbyte.integrations.destination.customerio.batch

/**
 * Represents the identifier type used to match people in Customer.io.
 *
 * Customer.io supports three identifier types in their batch API:
 * - email: The person's email address (case-insensitive)
 * - id: A case-sensitive unique identifier assigned by the user (e.g. backend user ID)
 * - cio_id: An immutable identifier generated by Customer.io
 *
 * @property recordField The field name in the Airbyte record (e.g. "person_email")
 * @property apiField The field name in the Customer.io batch API identifiers object (e.g. "email")
 */
enum class IdentifierType(val recordField: String, val apiField: String) {
    EMAIL("person_email", "email"),
    ID("person_id", "id"),
    CIO_ID("person_cio_id", "cio_id");

    companion object {
        fun fromConfigValue(value: String?): IdentifierType =
            when (value) {
                "id" -> ID
                "cio_id" -> CIO_ID
                else -> EMAIL
            }
    }
}
